"use strict";(globalThis.webpackChunkdoqumentation=globalThis.webpackChunkdoqumentation||[]).push([[1135],{59315(e,n,t){t.r(n),t.d(n,{assets:()=>c,contentTitle:()=>r,default:()=>d,frontMatter:()=>s,metadata:()=>i,toc:()=>l});const i=JSON.parse('{"id":"learning/courses/designing-and-leading-quantum-projects/introduction","title":"Introduction","description":"An introduction to a course designed to guide teams and organizations early in their launch of quantum initiatives.","source":"@site/i18n/ksh/docusaurus-plugin-content-docs/current/learning/courses/designing-and-leading-quantum-projects/introduction.mdx","sourceDirName":"learning/courses/designing-and-leading-quantum-projects","slug":"/learning/courses/designing-and-leading-quantum-projects/introduction","permalink":"/learning/courses/designing-and-leading-quantum-projects/introduction","draft":false,"unlisted":false,"editUrl":"https://github.com/JanLahmann/doQumentation/tree/main/docs/learning/courses/designing-and-leading-quantum-projects/introduction.mdx","tags":[],"version":"current","frontMatter":{"title":"Introduction","description":"An introduction to a course designed to guide teams and organizations early in their launch of quantum initiatives."},"sidebar":"tutorialsSidebar","previous":{"title":"Overview","permalink":"/learning/courses/designing-and-leading-quantum-projects/"},"next":{"title":"Early stages","permalink":"/learning/courses/designing-and-leading-quantum-projects/early-stages"}}');var a=t(74848),o=t(28453);const s={title:"Introduction",description:"An introduction to a course designed to guide teams and organizations early in their launch of quantum initiatives."},r="Welcome",c={},l=[{value:"Key players and audience",id:"key-players-and-audience",level:2},{value:"The IBM Quantum Network",id:"the-ibm-quantum-network",level:3},{value:"Quantum Innovation Centers",id:"quantum-innovation-centers",level:3},{value:"The quantum community",id:"the-quantum-community",level:3}];function u(e){const n={admonition:"admonition",h1:"h1",h2:"h2",h3:"h3",header:"header",li:"li",p:"p",strong:"strong",ul:"ul",...(0,o.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:["\n",(0,a.jsx)(n.admonition,{title:"Noch nit \xf6vversatz",type:"note",children:(0,a.jsx)(n.p,{children:"Die Sigg es noch nit \xf6vversatz. Ehr luurt \xfcch de \xe4nglesche Originalversion aan."})}),"\n","\n",(0,a.jsx)(n.header,{children:(0,a.jsx)(n.h1,{id:"welcome",children:"Welcome"})}),"\n",(0,a.jsx)(n.p,{children:"Welcome to Designing and Leading Quantum Projects, a course designed to inform teams and organizations on how to develop capabilities required for realizing quantum initiatives."}),"\n",(0,a.jsx)(n.p,{children:"This course is intended for academic, business, and organizational leadership in the early stages of building quantum projects. The lessons will cover common developmental stages and best practices identified by successful innovators in the field. Most of the content will be applicable across quantum projects broadly, though a few topics will be specific to a particular type of partnership. For example, grant writing might be more often applicable to academic researchers, though grants for startups and enterprises are also important in this ecosystem."}),"\n",(0,a.jsx)(n.p,{children:"This course is mostly non-technical. Technical jargon is limited to descriptions of concrete example workflows, example wording for grant proposals, and discussion of realistic deliverables and their constraints."}),"\n",(0,a.jsx)(n.p,{children:"The contents are organized as follows:"}),"\n",(0,a.jsxs)(n.ul,{children:["\n",(0,a.jsx)(n.li,{children:"Introduction"}),"\n",(0,a.jsx)(n.li,{children:"Early stages - things to consider and have in place prior to large purchases of quantum computing time, and prior to standing up a team"}),"\n",(0,a.jsx)(n.li,{children:"Standing up a team - key roles and responsibilities, attributes of successful teams"}),"\n",(0,a.jsx)(n.li,{children:"Grant writing - mapping best practices in general for grant writing in the context of quantum computing"}),"\n"]}),"\n",(0,a.jsx)(n.p,{children:"Join us for this deep dive into building successful quantum projects!"}),"\n",(0,a.jsx)(n.h2,{id:"key-players-and-audience",children:"Key players and audience"}),"\n",(0,a.jsx)(n.p,{children:"Below is a brief description of several key players in this ecosystem and potential audiences for this course."}),"\n",(0,a.jsx)(n.h3,{id:"the-ibm-quantum-network",children:"The IBM Quantum Network"}),"\n",(0,a.jsx)(n.p,{children:"The IBM Quantum Network is a worldwide collective shaping the future of quantum computing. The hundreds of partners in the Network include Fortune 500 companies, universities, laboratories, and startups, all helping to build a quantum economy. Partnership in the Network includes access to exclusive meetings and select channels where the latest ideas in quantum are shared. IBM Quantum Network partners collaborate even outside these events, and benefit from close working relationships."}),"\n",(0,a.jsx)(n.p,{children:"Every partner in the IBM Quantum Network is different, but some coarse-binned categories are useful for context, such as startups, global systems integrators (GSIs), academic institutions, non-academic research institutions, and large enterprises."}),"\n",(0,a.jsx)(n.p,{children:"Many of the guidelines and practices shared in this course were developed and field-tested by partners in the IBM Quantum Network."}),"\n",(0,a.jsxs)(n.p,{children:[(0,a.jsx)(n.strong,{children:"Startups:"})," Startups are agile, innovation\u2011driven companies that rapidly turn new ideas into scalable business solutions. In the quantum computing ecosystem, they play a pivotal role by accelerating technical breakthroughs, commercializing niche capabilities, and bridging cutting\u2011edge research with real\u2011world applications. Their speed and specialization help catalyze growth across the entire industry."]}),"\n",(0,a.jsxs)(n.p,{children:[(0,a.jsx)(n.strong,{children:"Global systems integrators (GSIs):"})," Global systems integrators (GSIs) are large, end\u2011to\u2011end technology and services firms that help organizations modernize, integrate, and scale complex digital solutions. In the quantum computing ecosystem, they play a crucial role by enabling enterprise\u2011grade adoption at a global scale. Their broad industry reach helps turn quantum innovation into operational impact."]}),"\n",(0,a.jsxs)(n.p,{children:[(0,a.jsx)(n.strong,{children:"Academic institutions:"})," These are universities, colleges, or consortia of educational institutions. In the quantum computing ecosystem, they play a central role by pushing the boundaries of theory and experimentation while training the next generation of quantum scientists and engineers. Their discoveries and expertise form the bedrock on which other organizations can build their quantum impact."]}),"\n",(0,a.jsxs)(n.p,{children:[(0,a.jsx)(n.strong,{children:"Research institutions:"})," These are specialized organizations, like national labs, focused on advancing scientific and technical knowledge through dedicated, often mission\u2011driven R&D. In the quantum computing ecosystem, they play a vital role by generating breakthrough discoveries, developing enabling technologies, and providing deep domain expertise that fuels innovation across industry and academia. Their educational initiatives are often focused more on training rising researchers and less on classroom education."]}),"\n",(0,a.jsxs)(n.p,{children:[(0,a.jsx)(n.strong,{children:"Enterprise organizations:"})," Enterprise organizations are established companies that apply technology to solve real business challenges, optimize operations, and create competitive advantage at scale. In the quantum computing ecosystem, they play a key role by identifying high\u2011value use cases, funding applied innovation, and piloting solutions that demonstrate measurable impact in real\u2011world environments."]}),"\n",(0,a.jsx)(n.h3,{id:"quantum-innovation-centers",children:"Quantum Innovation Centers"}),"\n",(0,a.jsxs)(n.p,{children:[(0,a.jsx)(n.strong,{children:"Quantum Innovation Centers (QICs)"})," serve as elite centers of expertise in the growing and ever-changing quantum ecosystem. Many operate as a hub, an industry or academic leader growing a quantum community by partnering with IBM\xae directly, and serving as a central contact point for other organizations. The QIC itself may be any of the organization types mentioned above (academic institution, large enterprise, and so on)."]}),"\n",(0,a.jsxs)(n.p,{children:["The resulting community around an IBM QIC has the potential to meet local needs through a bottom-up approach, to offer a wider variety of quantum computing access plans, and to leverage the community for broader expertise. This can be especially important for smaller organizations and startups. As an IBM QIC, you establish your leadership in the field and build important industry connections - and you are contributing to the ongoing growth of the quantum community. ",(0,a.jsx)(n.strong,{children:"Collaborating with a QIC could facilitate more competitive applications for governmental and private funding."})]}),"\n",(0,a.jsx)(n.p,{children:"Some QICs have their own IBM Quantum system on premises. This can be very important when, for example, working with data that cannot legally or responsibly be shared over the Internet, or across international borders."}),"\n",(0,a.jsx)(n.h3,{id:"the-quantum-community",children:"The quantum community"}),"\n",(0,a.jsx)(n.p,{children:"The broader community is driving quantum computing forward by lowering barriers to entry and amplifying impact through both education and open-source tooling. At universities, community-led teaching initiatives - like bootcamps, hackathons, open syllabi, and student clubs - equip learners with hands-on skills early, align curricula with fast-moving industry practices, and create on-ramps for diverse talent to contribute. At the same time, community contributions to Qiskit code, its documentation, and the IBM Quantum Learning platform, make best practices discoverable and shorten the path from idea to implementation. Together, this virtuous cycle of open education and open-source development expands the talent pipeline, standardizes shared tooling, and turns cutting-edge quantum concepts into accessible, collaborative progress."})]})}function d(e={}){const{wrapper:n}={...(0,o.R)(),...e.components};return n?(0,a.jsx)(n,{...e,children:(0,a.jsx)(u,{...e})}):u(e)}},28453(e,n,t){t.d(n,{R:()=>s,x:()=>r});var i=t(96540);const a={},o=i.createContext(a);function s(e){const n=i.useContext(o);return i.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function r(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:s(e.components),i.createElement(o.Provider,{value:n},e.children)}}}]);